from flask import Flask, render_template, request, g, redirect, url_for, session
import sqlite3
import os
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(Config.DATABASE_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Simple mock login for functionality
        if username == 'admin' and password == 'crestpath2024':
            session['user'] = 'admin'
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials.")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/manifests')
def manifests():
    if 'user' not in session:
        return redirect(url_for('login'))
    db = get_db()
    items = db.execute("SELECT * FROM inventory_manifests LIMIT 10").fetchall()
    return render_template('manifests.html', items=items)

@app.route('/manifests/search')
def search_manifests():
    if 'user' not in session:
        return redirect(url_for('login'))

    query = request.args.get('q', '')

    # MEDIUM DIFFICULTY FILTER
    # The developer tried to block common SQL keywords but used a case-sensitive check
    forbidden = ["SELECT", "UNION", "FROM", "WHERE", "--", "OR", "AND"]
    for word in forbidden:
        if word in query:
            return render_template('manifests.html', error=f"Security Filter Blocked: '{word}' detected!")

    db = get_db()
    try:
        # Vulnerable to UNION SQLi
        sql = f"SELECT sku, location, quantity FROM inventory_manifests WHERE sku LIKE '%{query}%'"
        results = db.execute(sql).fetchall()
    except Exception as e:
        return render_template('manifests.html', error=f"Database Error: {str(e)}")

    return render_template('manifests.html', results=results, query=query)

@app.route('/logs')
def shipping_logs():
    if 'user' not in session:
        return redirect(url_for('login'))

    # RED HERRING: Looks vulnerable to ORDER BY injection, but is safely whitelisted
    sort_by = request.args.get('sort', 'timestamp')
    valid_columns = ['id', 'destination', 'status', 'timestamp']
    if sort_by not in valid_columns:
        sort_by = 'timestamp'

    db = get_db()
    logs = db.execute(f"SELECT * FROM shipping_logs ORDER BY {sort_by} DESC LIMIT 20").fetchall()
    return render_template('logs.html', logs=logs)

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

