{% extends "base.html" %}
{% block content %}
<div class="card">
    <h2>Inventory Manifests</h2>
    <form action="/manifests/search" method="GET">
        <input type="text" name="q" placeholder="Search by SKU (e.g., CP-)" value="{{ query or '' }}">
        <button type="submit">Search</button>
    </form>

    {% if error %}<div class="error" style="margin-top: 20px;">{{ error }}</div>{% endif %}

    {% if results %}
        <h3>Search Results for "{{ query }}":</h3>
        <table>
            <tr><th>SKU</th><th>Location</th><th>Quantity</th></tr>
            {% for row in results %}
            <tr>
                <td>{{ row[0] }}</td>
                <td>{{ row[1] }}</td>
                <td>{{ row[2] }}</td>
            </tr>
            {% endfor %}
        </table>
    {% elif items %}
        <h3>Recent Manifests:</h3>
        <table>
            <tr><th>SKU</th><th>Location</th><th>Quantity</th></tr>
            {% for item in items %}
            <tr>
                <td>{{ item['sku'] }}</td>
                <td>{{ item['location'] }}</td>
                <td>{{ item['quantity'] }}</td>
            </tr>
            {% endfor %}
        </table>
    {% endif %}
</div>
{% endblock %}
